package main

// Define the modulus
const MOD int64 = 1e9 + 7

// Global storage for precomputed factorials (up to 100000)
var fact []int64

// power calculates (base^exp) % MOD
func power(base, exp int64) int64 {
	res := int64(1)
	base %= MOD
	for exp > 0 {
		if exp%2 == 1 {
			res = (res * base) % MOD
		}
		base = (base * base) % MOD
		exp /= 2
	}
	return res
}

// modInverse calculates modular multiplicative inverse using Fermat's Little Theorem
func modInverse(n int64) int64 {
	return power(n, MOD-2)
}

// precomputeFactorials initializes the factorial array up to maxN
func precomputeFactorials(maxN int64) {
	// We need factorials up to maxN (which is N-1, max 10^5-1)
	size := int(maxN + 1)
	fact = make([]int64, size)
	fact[0] = 1
	for i := int64(1); i <= maxN; i++ {
		fact[i] = (fact[i-1] * i) % MOD
	}
}

// nCr calculates n choose r modulo MOD
func nCr(n, r int64) int64 {
	if r < 0 || r > n {
		return 0
	}
	if r == 0 || r == n {
		return 1
	}
	if r > n/2 {
		r = n - r
	}

	// Check if factorials are precomputed up to n
	if int(n) >= len(fact) {
		// Should not happen given constraints and setup, but good practice
		// If n was larger than precomputed limit, we'd need dynamic calculation or larger precomputation.
		return 0 
	}

	numerator := fact[n]
	denominator := (fact[r] * fact[n-r]) % MOD

	return (numerator * modInverse(denominator)) % MOD
}

func solve(n int64, pos int64, k int64) int64 {
	// N is up to 10^5, so we precompute factorials up to N-1.
	// Since N is an input, we must ensure precomputation happens based on N.
	// In a real competitive programming environment, precomputation often happens once outside the function calls.
	// Here, we call it inside, assuming this function might be called multiple times or we handle initialization context.
	// We ensure maxN is at least n-1.
	if n > 0 {
		precomputeFactorials(n - 1)
	} else {
		return 0
	}

	// L: number of people to the left of pos (indices 0 to pos-1)
	L := pos
	// R: number of people to the right of pos (indices pos+1 to n-1)
	R := n - 1 - pos

	// Total ways to achieve K visible people from the sides
	totalSideWays := int64(0)

	// We need k_L + k_R = K
	// k_L must be between max(0, K-R) and min(K, L)

	// Start k_L from the minimum required value
	start_kL := k - R
	if start_kL < 0 {
		start_kL = 0
	}

	// End k_L at the maximum possible value
	end_kL := k
	if end_kL > L {
		end_kL = L
	}

	for kL := start_kL; kL <= end_kL; kL++ {
		kR := k - kL

		// Check if kR is valid given R (although loop bounds should handle this if derived correctly)
		if kR < 0 || kR > R {
			continue 
		}

		// Ways to choose kL visible from L people: C(L, kL)
		waysL := nCr(L, kL)

		// Ways to choose kR visible from R people: C(R, kR)
		waysR := nCr(R, kR)

		// Total ways for this specific split (kL, kR)
		ways := (waysL * waysR) % MOD

		totalSideWays = (totalSideWays + ways) % MOD
	}

	// The person at pos can choose 'L' or 'R' independently (2 choices), and this choice does not affect the count K.
	// Final answer = 2 * totalSideWays
	result := (2 * totalSideWays) % MOD

	return result
}
