const MOD = 1000000007n;

/**
 * Modular exponentiation: (base^exp) % MOD
 * @param {bigint} base 
 * @param {bigint} exp 
 * @returns {bigint}
 */
function power(base, exp) {
    let res = 1n;
    base %= MOD;
    while (exp > 0n) {
        if (exp % 2n === 1n) {
            res = (res * base) % MOD;
        }
        base = (base * base) % MOD;
        exp /= 2n;
    }
    return res;
}

/**
 * Modular multiplicative inverse using Fermat's Little Theorem: n^(MOD-2) % MOD
 * @param {bigint} n 
 * @returns {bigint}
 */
function modInverse(n) {
    return power(n, MOD - 2n);
}

/**
 * Precalculates factorials and inverse factorials up to maxN.
 * @param {number} maxN 
 * @returns {{fact: bigint[], invFact: bigint[]}}
 */
function precomputeFactorials(maxN) {
    const fact = new Array(maxN + 1);
    const invFact = new Array(maxN + 1);
    fact[0] = 1n;
    for (let i = 1; i <= maxN; i++) {
        fact[i] = (fact[i - 1] * BigInt(i)) % MOD;
    }

    invFact[maxN] = modInverse(fact[maxN]);
    for (let i = maxN - 1; i >= 0; i--) {
        invFact[i] = (invFact[i + 1] * BigInt(i + 1)) % MOD;
    }

    return { fact, invFact };
}

/**
 * Calculates nCr % MOD
 * @param {number} n 
 * @param {number} r 
 * @param {{fact: bigint[], invFact: bigint[]}} precomputed 
 * @returns {bigint}
 */
function combinations(n, r, precomputed) {
    if (r < 0 || r > n) {
        return 0n;
    }
    const { fact, invFact } = precomputed;

    // nCr = n! / (r! * (n-r)!)
    let result = fact[n];
    result = (result * invFact[r]) % MOD;
    result = (result * invFact[n - r]) % MOD;
    return result;
}


function solve(n, pos, k) {
    if (n === 0) return 0;

    // Precompute factorials up to N
    const precomputed = precomputeFactorials(n);

    // L: number of people to the left of pos (indices 0 to pos-1)
    const L = pos;

    // R: number of people to the right of pos (indices pos+1 to n-1)
    const R = n - 1 - pos;

    let totalWaysLR = 0n;

    // We need k_L + k_R = k, where 
    // k_L is chosen from L people (must choose 'L')
    // k_R is chosen from R people (must choose 'R')

    // Determine the loop range for k_L:
    // 1. k_L >= 0
    // 2. k_L <= L
    // 3. k_R = k - k_L >= 0  => k_L <= k
    // 4. k_R = k - k_L <= R  => k_L >= k - R

    const start_kL = Math.max(0, k - R);
    const end_kL = Math.min(k, L);

    for (let kL = start_kL; kL <= end_kL; kL++) {
        const kR = k - kL;

        // Ways to choose kL visible people from L: C(L, kL)
        const waysL = combinations(L, kL, precomputed);

        // Ways to choose kR visible people from R: C(R, kR)
        const waysR = combinations(R, kR, precomputed);

        // Total ways for this specific split (kL, kR)
        const ways = (waysL * waysR) % MOD;

        totalWaysLR = (totalWaysLR + ways) % MOD;
    }

    // The person at pos has 2 choices ('L' or 'R'), which multiply the total count.
    const finalAnswer = (totalWaysLR * 2n) % MOD;

    // Return as standard Number type as per typical JS function signatures unless BigInt is strictly required by contest environment for return type, but since the modulo is 10^9+7, standard JS number (up to 2^53) might overflow intermediate steps if we didn't use BigInt throughout. Since we used BigInt, casting the final result is safe.
    return Number(finalAnswer);
}
