package main

import "fmt"

const MOD int64 = 1000000007

var fact []int64
var invFact []int64

// Modular exponentiation: (base^exp) % MOD
func power(base, exp int64) int64 {
    res := int64(1)
    base %= MOD
    for exp > 0 {
        if exp%2 == 1 {
            res = (res * base) % MOD
        }
        base = (base * base) % MOD
        exp /= 2
    }
    return res
}

// Modular inverse: n^(MOD-2) % MOD
func modInverse(n int64) int64 {
    return power(n, MOD-2)
}

// Precompute factorials and inverse factorials up to maxN
func precomputeFactorials(maxN int) {
    if maxN < 0 {
        return
    }
    fact = make([]int64, maxN+1)
    invFact = make([]int64, maxN+1)

    fact[0] = 1
    for i := 1; i <= maxN; i++ {
        fact[i] = (fact[i-1] * int64(i)) % MOD
    }

    invFact[maxN] = modInverse(fact[maxN])
    for i := maxN - 1; i >= 0; i-- {
        invFact[i] = (invFact[i+1] * int64(i+1)) % MOD
    }
}

// Combinations: nCk % MOD
func nCr(N, K int64) int64 {
    if K < 0 || K > N {
        return 0
    }
    N_int := int(N)
    K_int := int(K)

    numerator := fact[N_int]
    denominator := (invFact[K_int] * invFact[N_int-K_int]) % MOD

    return (numerator * denominator) % MOD
}

func solve(n int64, pos int64, k int64) int64 {
    // Maximum value N we need for combinations is n.
    // Since n <= 10^5, we precompute up to 100000.
    // We ensure precomputation is done only once, if possible, 
    // but in a strict function signature environment, we handle it safely.
    if fact == nil || len(fact) <= int(n) {
        precomputeFactorials(int(n))
    }

    // People to the left of pos: 0 to pos-1
    PL := pos
    // People to the right of pos: pos+1 to n-1
    PR := n - 1 - pos

    // We need L_count + R_count = k
    // L_count must be between 0 and PL.
    // R_count = k - L_count must be between 0 and PR.

    // L_count >= 0
    // L_count <= PL
    // k - L_count >= 0  => L_count <= k
    // k - L_count <= PR  => L_count >= k - PR

    startL := int64(0)
    if k-PR > startL {
        startL = k - PR
    }

    endL := int64(0)
    if k < endL {
        // This case won't happen since k >= 0 and endL starts at 0
    }
    if PL < endL {
        endL = PL
    }
    if k < endL {
        endL = k
    }

    totalWaysOthers := int64(0)

    for LCount := startL; LCount <= endL; LCount++ {
        RCount := k - LCount

        // Safety check (though bounds should handle this)
        if LCount < 0 || LCount > PL || RCount < 0 || RCount > PR {
            continue
        }

        // Ways to choose LCount 'L's out of PL people
        waysL := nCr(PL, LCount)

        // Ways to choose RCount 'R's out of PR people
        waysR := nCr(PR, RCount)

        // Total ways for this specific split (LCount, RCount)
        contribution := (waysL * waysR) % MOD

        totalWaysOthers = (totalWaysOthers + contribution) % MOD
    }

    // The person at pos can choose 'L' or 'R' (2 ways), independent of the counts.
    finalAnswer := (totalWaysOthers * 2) % MOD

    return finalAnswer
}
