var fact []int64
var invFact []int64

// Precomputes factorials and inverse factorials up to max_val
func precomputeFactorials(max_val int64) {
	fact = make([]int64, max_val+1)
	invFact = make([]int64, max_val+1)
	fact[0] = 1
	for i := int64(1); i <= max_val; i++ {
		fact[i] = (fact[i-1] * i) % MOD
	}

	invFact[max_val] = power(fact[max_val], MOD-2)
	for i := max_val - 1; i >= 0; i-- {
		invFact[i] = (invFact[i+1] * (i + 1)) % MOD
	}
}

// Modular exponentiation (base^exp) % MOD
