func nCr(n, r int64) int64 {
	if r < 0 || r > n {
		return 0
	}
	if n > MAX_N {
		// Should not happen based on constraints
		panic("N exceeds precomputed limit")
	}

	numerator := fact[n]
	denominator := (invFact[r] * invFact[n-r]) % MOD
	return (numerator * denominator) % MOD
