    // Ensure factorials are precomputed up to N
    if fact == nil || len(fact) <= int(n) {
        precomputeFactorials(MAX_N)
    }

	L_count := pos
	R_count := n - 1 - pos

	total_sum := int64(0)

	// We iterate over k_L, the number of visible people on the left side.
	// k_L must satisfy:
	// 1. 0 <= k_L <= L_count
	// 2. k_R = K - k_L must satisfy 0 <= k_R <= R_count

	// From k_R >= 0: K - k_L >= 0 => k_L <= K
	// From k_R <= R_count: K - k_L <= R_count => k_L >= K - R_count

	k_L_min := int64(0)
	k_L_min = int64(math.Max(float64(k_L_min), float64(k - R_count)))

	k_L_max := int64(math.Min(float64(k_L_max), float64(pos)))
	k_L_max = int64(math.Min(float64(k_L_max), float64(k)))

    // Re-setting bounds correctly using standard comparisons
    k_L_min = int64(math.Max(0.0, float64(k - R_count)))
    k_L_max = int64(math.Min(float64(pos), float64(k)))


	for k_L := k_L_min; k_L <= k_L_max; k_L++ {
		k_R := k - k_L

		// Number of ways to choose k_L visible people from L_count
		ways_L := nCr(L_count, k_L)

		// Number of ways to choose k_R visible people from R_count
		ways_R := nCr(R_count, k_R)

		// Total ways for this split (k_L, k_R)
		ways_split := (ways_L * ways_R) % MOD

		total_sum = (total_sum + ways_split) % MOD
	}

	// The person at pos can choose 'L' or 'R' (2 ways), which multiplies the result.
	result := (2 * total_sum) % MOD

	return result
