package main

import "math"

const MOD int64 = 1e9 + 7
const MAX_N = 100000

var fact []int64
var invFact []int64

// Modular exponentiation: (base^exp) % mod
func power(base, exp int64) int64 {
	res := int64(1)
	base %= MOD
	for exp > 0 {
		if exp%2 == 1 {
			res = (res * base) % MOD
		}
		base = (base * base) % MOD
		exp /= 2
	}
	return res
}

// Modular inverse using Fermat's Little Theorem: a^(M-2) % M
func modInverse(n int64) int64 {
	return power(n, MOD-2)
}

// Precomputes factorials and inverse factorials up to max
func precomputeFactorials(max int) {
	if len(fact) > max {
		return // Already precomputed enough
	}

	fact = make([]int64, max+1)
	invFact = make([]int64, max+1)
	fact[0] = 1
	for i := 1; i <= max; i++ {
		fact[i] = (fact[i-1] * int64(i)) % MOD
	}

	if max >= 0 {
		// Compute inverse of fact[max] first
		invFact[max] = modInverse(fact[max])
		for i := max - 1; i >= 0; i-- {
			invFact[i] = (invFact[i+1] * int64(i+1)) % MOD
		}
	}
}

// Combinations C(n, r) % MOD
func nCr(n, r int) int64 {
	if r < 0 || r > n {
		return 0
	}
	if n > MAX_N {
		// This should not happen based on constraints N<=10^5
		return 0 
	}

	num := fact[n]
	den := (invFact[r] * invFact[n-r]) % MOD
	return (num * den) % MOD
}


func solve(n int64, pos int64, k int64) int64 {
    // Ensure factorials are precomputed up to N-1, max 100000
    if n > 0 && n-1 > MAX_N {
        // Safety break, although constraints say N <= 10^5
        return 0
    }
    precomputeFactorials(int(math.Min(float64(n-1), float64(MAX_N))))

    if n == 1 {
        // Only person at pos=0. K must be 0. 2 choices for D_0.
        if k == 0 {
            return 2
        }
        return 0
    }

    // We need to calculate 2 * C(N-1, K) mod MOD
    N_prime := int(n - 1)
    K := int(k)

    combinations := nCr(N_prime, K)

    // Total ways = 2 * C(N-1, K)
    result := (2 * combinations) % MOD

    return result
}
